+            if len(label) >= FSLABEL_MAX:
+                raise ValueError('label too long for ioctl buffer')
+            buffer = bytearray(FSLABEL_MAX)
+            buffer[:len(label)] = label
+            buffer[len(label)] = 0
+            fcntl.ioctl(fh.fileno(), FS_IOC_SETFSLABEL, buffer)
